/**
 * Static require() map for React Native (Metro). Keys are both the 4-digit
 * COMPE code (e.g. "0341") and the 8-digit ISPB (e.g. "60701190"); values
 * are Metro asset module ids, usable directly as an <Image> source.
 *
 * Importing this entry bundles ALL logos into the app.
 */
declare const logos: Record<string, number>;
export default logos;
export { logos };
